<span class="line"><span style="color:#F9E2AF;">    tokio</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;">time</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">sleep</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">wait</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;">.</span><span style="color:#CBA6F7;">await</span><span style="color:#9399B2;">;</span></span>
