<span class="line"><span style="color:#CDD6F4;">                error</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> AgentError</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">Parse</span><span style="color:#9399B2;">(</span><span style="color:#F9E2AF;">ParseError</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">MalformedResponse</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">msg</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">clone</span><span style="color:#9399B2;">())),</span></span>
